24234 /// Checks if the quadratic mean deviation is less than 90% of the mean size.
24235 static bool checkTreeSizes(ArrayRef<std::pair<unsigned, unsigned>> Sizes) {
24236   unsigned Num = 0;
24237   uint64_t Sum = std::accumulate(
24238       Sizes.begin(), Sizes.end(), static_cast<uint64_t>(0),
24239       [&](uint64_t V, const std::pair<unsigned, unsigned> &Val) {
24240         unsigned Size = Val.first;
24241         if (Size == 1)
24242           return V;
24243         ++Num;
24244         return V + Size;
24245       });
24246   if (Num == 0)
24247     return true;
24248   uint64_t Mean = Sum / Num;
24249   if (Mean == 0)
24250     return true;
24251   uint64_t Dev = std::accumulate(
24252                      Sizes.begin(), Sizes.end(), static_cast<uint64_t>(0),
24253                      [&](uint64_t V, const std::pair<unsigned, unsigned> &Val) {
24254                        unsigned P = Val.first;
24255                        if (P == 1)
24256                          return V;
24257                        return V + (P - Mean) * (P - Mean);
24258                      }) /
24259                  Num;
24260   return Dev * 96 / (Mean * Mean) == 0;
24261 }
